"$file = 'src/pages/AdminSettings.tsx'\n$content = Get-Content $file -Raw\n\n# Replace the problematic size_mb check with typeof safety\n$old = \"{safeStatus.size_mb !== undefined && safeStatus.size_mb !== null && (\"\n$old += \"`n            <div className=\\\\"\"text-xs text-muted-foreground mb-2\\\"\">\"\n$old += \"`n              <span className=\\\\"\"text-foreground font-medium\\\"\">Занято:</span> {safeStatus.size_mb ? safeStatus.size_mb.toFixed(2) : '0'} МБ\"\n$old += \"`n            </div>\"\n$old += \"`n          )}\"\n\n$new = \"{typeof safeStatus.size_mb === 'number' && (\"\n$new += \"`n            <div className=\\\\"\"text-xs text-muted-foreground mb-2\\\"\">\"\n$new += \"`n              <span className=\\\\"\"text-foreground font-medium\\\"\">Занято:</span> {safeStatus.size_mb.toFixed(2)} МБ\"\n$new += \"`n            </div>\"\n$new += \"`n          )}\"\n\nif ($content -match [regex]::Escape($old)) {\n    $content = $content -replace [regex]::Escape($old), $new\n    Set-Content $file $content -NoNewline\n    Write-Host 'Fixed!' -ForegroundColor Green\n} else {\n    Write-Host 'Pattern not found - manual check needed' -ForegroundColor Yellow\n}"